import{_ as l,o as t,c as i,ag as r}from"./chunks/framework.eQLvDOR_.js";const k=JSON.parse('{"title":"skill-lifecycle","description":"","frontmatter":{"title":"skill-lifecycle","concept":"Skill Lifecycle","concept_id":"skill-lifecycle","aliases":["技能生命周期","Agent-Skills-Workflow"],"sources":["02_Library/ADK_Agent_Skills/[ADK_Agent_Skills] Production-grade engineering skills for AI coding agents.md"],"related_concepts":["[[agentic-patterns]]"],"created_at":"2026-04-07","last_compiled":"2026-04-07"},"headers":[],"relativePath":"wiki/concepts/skill-lifecycle.md","filePath":"wiki/concepts/skill-lifecycle.md","lastUpdated":null}'),s={name:"wiki/concepts/skill-lifecycle.md"};function n(o,e,a,c,g,h){return t(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="skill-lifecycle-技能生命周期" tabindex="-1">Skill Lifecycle (技能生命周期) <a class="header-anchor" href="#skill-lifecycle-技能生命周期" aria-label="Permalink to &quot;Skill Lifecycle (技能生命周期)&quot;">​</a></h1><h2 id="核心流程-the-6-phases" tabindex="-1">核心流程 (The 6 Phases) <a class="header-anchor" href="#核心流程-the-6-phases" aria-label="Permalink to &quot;核心流程 (The 6 Phases)&quot;">​</a></h2><p>生产级 AI 编码智能体应遵循与资深工程师一致的 6 阶段开发周期：</p><ol><li><strong>DEFINE (/spec)</strong>：定义构建目标。原则：<strong>Spec before code (先规范后代码)</strong>。</li><li><strong>PLAN (/plan)</strong>：规划实现路径。原则：<strong>Small, atomic tasks (小而原子的任务)</strong>。</li><li><strong>BUILD (/build)</strong>：增量代码实现。原则：<strong>One slice at a time (一次实现一个切片)</strong>。</li><li><strong>VERIFY (/test)</strong>：验证功能正确。原则：<strong>Tests are proof (测试即证明)</strong>。</li><li><strong>REVIEW (/review)</strong>：合入前的质量关卡。原则：<strong>Improve code health (提升代码健康度)</strong>。</li><li><strong>SHIP (/ship)</strong>：发布上线。原则：<strong>Faster is safer (快速发布更安全)</strong>。</li><li><strong>EVOLVE (自动学习/演化)</strong>：Agent-Managed Skills。高阶 Agent 在多次完成相似复杂任务并提取模式后，系统能够自我策展，将散落的操作经历固化编写为一个全新的高优技能配置。（来源：<a href="/s/webclips/library/Agent_Architecture/Agent_Architecture - Hermes Agent 从中级到高级进阶指南.html">[Agent_Architecture] Hermes Agent 从中级到高级进阶指南.md</a>）</li></ol><h2 id="技能解析-skill-anatomy" tabindex="-1">技能解析 (Skill Anatomy) <a class="header-anchor" href="#技能解析-skill-anatomy" aria-label="Permalink to &quot;技能解析 (Skill Anatomy)&quot;">​</a></h2><p>每个 Agent Skill 并非简单的提示词，而是一个包含以下结构的<strong>结构化工作流</strong>：</p><ul><li><strong>Overview</strong>：技能用途。</li><li><strong>Trigger</strong>：何时触发。</li><li><strong>Process</strong>：单步工作流与检查点。</li><li><strong>Anti-rationalization</strong>：<strong>反辩护机制</strong>。列出 Agent 可能跳过步骤的借口（如“我稍后补测试”）并给出强制执行理由。</li><li><strong>Verification</strong>：证据要求。不接受“似乎正确”，必须有测试通过或运行日志。</li></ul><h2 id="核心理念" tabindex="-1">核心理念 <a class="header-anchor" href="#核心理念" aria-label="Permalink to &quot;核心理念&quot;">​</a></h2><blockquote><p>&quot;Skills bake in best practices from Google&#39;s engineering culture. They are workflows agents follow, not reference docs they read.&quot;</p></blockquote><hr><h2 id="实践指南" tabindex="-1">实践指南 <a class="header-anchor" href="#实践指南" aria-label="Permalink to &quot;实践指南&quot;">​</a></h2><ul><li><strong>Spec-First 模版</strong>：在开始任何 Skill 之前，强制要求 Agent 生成一个 <code>SPEC.md</code>。</li><li><strong>反辩护机制检查</strong>：自查 Skill 说明中是否包含“如果环境不匹配，请不要尝试猜测，直接报错”这类硬约束。</li><li><strong>演化审计</strong>：每 10 次自动演化任务后，人类应对固化的 Skill 进行一次代码审计，确保没有引入“针对特定项目的脏逻辑”。</li></ul><hr><h2 id="参考链接" tabindex="-1">参考链接 <a class="header-anchor" href="#参考链接" aria-label="Permalink to &quot;参考链接&quot;">​</a></h2><ul><li><a href="/s/webclips/library/ADK_Agent_Skills/ADK_Agent_Skills - Production-grade engineering skills for AI coding agents.html">[ADK_Agent_Skills] Production-grade engineering skills for AI coding agents</a></li><li><a href="/s/webclips/library/Agent_Architecture/Agent_Architecture - Hermes Agent 从中级到高级进阶指南.html">[Agent_Architecture] Hermes Agent 从中级到高级进阶指南.md</a></li></ul>',15)])])}const A=l(s,[["render",n]]);export{k as __pageData,A as default};
